import{_ as a,o as i,c as r,ag as o}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"VAT Management","description":"","frontmatter":{},"headers":[],"relativePath":"features/vat.md","filePath":"features/vat.md"}'),n={name:"features/vat.md"};function t(l,e,s,c,d,h){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="vat-management" tabindex="-1">VAT Management <a class="header-anchor" href="#vat-management" aria-label="Permalink to &quot;VAT Management&quot;">​</a></h1><p>Track, calculate, and manage your Value Added Tax (VAT) obligations with period locking and deadline tracking.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The VAT page gives you a clear view of your tax position:</p><ul><li><strong>VAT collected</strong> — Tax charged on your invoices</li><li><strong>VAT deductible</strong> — Tax paid on your business expenses</li><li><strong>Net VAT</strong> — The amount you owe (or can reclaim)</li></ul><h2 id="vat-periods" tabindex="-1">VAT periods <a class="header-anchor" href="#vat-periods" aria-label="Permalink to &quot;VAT periods&quot;">​</a></h2><p>VAT is organized by period (monthly or quarterly, depending on your jurisdiction):</p><ul><li>View VAT calculations per period</li><li>See detailed breakdowns by VAT rate</li><li>Track which periods have been filed</li></ul><h2 id="period-locking" tabindex="-1">Period locking <a class="header-anchor" href="#period-locking" aria-label="Permalink to &quot;Period locking&quot;">​</a></h2><p>After filing your VAT return, lock the period to prevent accidental changes:</p><ol><li>Go to the VAT page</li><li>Select the period you&#39;ve filed</li><li>Click <strong>Lock Period</strong></li></ol><h3 id="what-locking-does" tabindex="-1">What locking does <a class="header-anchor" href="#what-locking-does" aria-label="Permalink to &quot;What locking does&quot;">​</a></h3><ul><li>Prevents editing or deleting invoices and expenses in the locked period</li><li>Shows a warning banner on documents within locked periods</li><li>Ensures your filed numbers remain consistent with your records</li></ul><h3 id="unlocking" tabindex="-1">Unlocking <a class="header-anchor" href="#unlocking" aria-label="Permalink to &quot;Unlocking&quot;">​</a></h3><p>If you need to make corrections after locking:</p><ol><li>Go to the VAT page</li><li>Find the locked period</li><li>Click <strong>Unlock</strong></li><li>Make your corrections</li><li>Re-lock when done</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Only unlock periods when you need to file a correction. Frequent unlocking defeats the purpose of the compliance safeguard.</p></div><h2 id="deadline-tracking" tabindex="-1">Deadline tracking <a class="header-anchor" href="#deadline-tracking" aria-label="Permalink to &quot;Deadline tracking&quot;">​</a></h2><p>MyCompanyDesk tracks VAT filing deadlines based on your country:</p><ul><li>Visual indicators for upcoming deadlines</li><li>Warnings when a deadline is approaching</li><li>Clear status showing which periods need attention</li></ul><h2 id="country-indicator" tabindex="-1">Country indicator <a class="header-anchor" href="#country-indicator" aria-label="Permalink to &quot;Country indicator&quot;">​</a></h2><p>Your VAT settings respect your company&#39;s country of registration. This affects:</p><ul><li>Standard and reduced VAT rates</li><li>Filing period structure (monthly/quarterly)</li><li>Deadline calculations</li><li>Reverse charge applicability</li></ul><h2 id="reverse-charge" tabindex="-1">Reverse charge <a class="header-anchor" href="#reverse-charge" aria-label="Permalink to &quot;Reverse charge&quot;">​</a></h2><p>For intra-EU business-to-business transactions, enable reverse charge:</p><ol><li>Make sure the customer has a valid EU VAT number</li><li>Enable <strong>Reverse Charge</strong> in Company &gt; Features</li><li>When creating an invoice for an EU B2B customer, select the reverse charge option</li><li>The invoice will show 0% VAT with the reverse charge notation</li></ol><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Lock periods immediately after filing to prevent accidental changes</li><li>Review the VAT report in <a href="/features/reports">Reports</a> for a broader view</li><li>Make sure both your VAT number and your customers&#39; VAT numbers are correctly entered</li><li>Use the bookkeeper/accountant dashboard profile for a VAT-focused view</li></ul>',28)])])}const g=a(n,[["render",t]]);export{p as __pageData,g as default};
